+        executed_steps.push(json!({
+            "ordinal": step.ordinal,
+            "phase": step.phase,
+            "purpose": step.purpose,
+            "command": step.command,
+            "command_line": step.command_line,
+            "approval_required": step.approval_required,
+            "side_effecting": step.side_effecting,
+            "notes": step.notes,
