+            return Ok(json!({
+                "status": "stopped-on-primitive-error",
+                "executed_steps": executed_steps,
+                "withheld_steps": withheld_steps,
+                "executed_count": executed_steps.len(),
+                "withheld_count": withheld_steps.len(),
