+fn canonical_command_alias(token: &str) -> Option<&'static str> {
+    match token {
+        "contract" => Some("guide"),
+        "workflow" => Some("plan"),
+        "why" => Some("explain"),
+        "run" => Some("do"),
+        "ls" => Some("list"),
+        "info" | "inspect" | "describe" => Some("show"),
+        "operations" | "operation" | "op" => Some("ops"),
+        "spec" => Some("schema"),
+        "example" => Some("examples"),
+        "preview" | "dry-run" => Some("simulate"),
+        _ => None,
+    }
